for (const item of $input.all()) {
  const mySystemPrompt = `## ROLE: Tarot Question Linter & Moderator
## TASK: Đánh giá [CÂU HỎI] của người dùng có phù hợp để trải bài Tarot hay không và phân loại xem đó là câu hỏi bốc bài hay giao tiếp thông thường.

## QUY TẮC ĐÁNH GIÁ:
1. isValid = true, pick_card = true:
- Người dùng đặt câu hỏi rõ ràng cần bốc bài Tarot (ví dụ: "Tình cảm sắp tới của tôi ra sao?", "Tôi có nên đổi việc không?", "Cho tôi một lời khuyên").
- reason BẮT BUỘC phải là "ok".

2. isValid = true, pick_card = false:
- Người dùng chỉ đang chào hỏi, cảm ơn, hoặc hỏi thêm về trải bài hiện tại (ví dụ: "Chào bạn", "Cảm ơn", "Giải thích thêm lá 2 đi", "Ý nghĩa lá này là gì?").
- reason phải là "conversational" (hệ thống sẽ tự gọi LLM riêng để trả lời).

3. isValid = false, pick_card = false:
- Câu hỏi quá ngắn, vô nghĩa (ví dụ: "hi", "asdasd").
- Chủ đề ngoài đời sống, vi phạm (ví dụ: giải toán, code, chửi thề, hỏi thời tiết).
- reason phải là một câu giải thích lịch sự lý do từ chối.

## OUTPUT FORMAT (JSON ONLY - KHÔNG bọc block code):
{"isValid": true, "pick_card": true, "reason": "ok"}`;

  const question = $('Check câu hỏi').first().json.body.question || "";

  const myUserPrompt = `### [CÂU HỎI ĐẦU VÀO CỦA KHÁCH HÀNG]\n"${question}"\n\nHãy phân tích và trả về đối tượng JSON đúng định dạng.`;

  item.json.bodyPayload = {
    model: "n8n2",
    messages: [
      { role: "system", content: mySystemPrompt },
      { role: "user", content: myUserPrompt }
    ],
    temperature: 0
  };
}

return $input.all();

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  let isValid = false;
  let pick_card = false;
  let reason = "Câu hỏi chưa rõ ràng hoặc không liên quan đến Tarot.";

  // 1. Trích xuất kết quả từ API
  let rawText = "";
  if (data.choices && data.choices[0] && data.choices[0].message) {
    rawText = data.choices[0].message.content || "";
  } else {
    rawText = data.output || data.text || "";
  }

  if (typeof rawText === 'object') {
    rawText = JSON.stringify(rawText);
  }
  rawText = rawText.trim();

  // Loại bỏ markdown code block nếu có
  if (rawText.includes('```')) {
    rawText = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();
  }

  try {
    const parsed = JSON.parse(rawText);
    isValid = parsed.isValid;
    pick_card = parsed.pick_card;
    reason = parsed.reason || "ok";
  } catch (e) {
    // Fallback bằng Regex
    const lowerText = rawText.toLowerCase();
    if (lowerText.includes('"isvalid": true') || lowerText.includes('isvalid: true')) {
      isValid = true;
      if (lowerText.includes('"pick_card": true') || lowerText.includes('pick_card: true')) {
        pick_card = true;
      }
      reason = "ok";
    } else {
      isValid = false;
      const match = rawText.match(/"reason"\s*:\s*"([^"]+)"/i);
      if (match && match[1]) {
        reason = match[1];
      }
    }
  }

  // 2. Ép kiểu chuẩn
  if (typeof isValid === 'string') {
    isValid = (isValid.toLowerCase() === 'true');
  } else {
    isValid = Boolean(isValid);
  }

  if (typeof pick_card === 'string') {
    pick_card = (pick_card.toLowerCase() === 'true');
  } else {
    pick_card = Boolean(pick_card);
  }

  // 3. Chuẩn hóa giá trị
  if (isValid && pick_card) {
    reason = "ok";
  } else if (!isValid && (!reason || reason === "ok" || reason === "undefined")) {
    reason = "Câu hỏi không phù hợp. Vui lòng đặt câu hỏi liên quan đến chủ đề Tarot.";
  }

  results.push({
    json: {
      output: {
        isValid: isValid,
        pick_card: pick_card,
        reason: reason,
        usage: data.usage || null,
        model: data.model || null
      }
    }
  });
}

return results;

for (const item of $input.all()) {
  const userMsg = $('Conversational tarot').first().json.body.message || "";
  const userProfile = $('Conversational tarot').first().json.body.userProfile || { name: 'lữ khách', gender: 'bạn', user_persona: '' };
  const userName = userProfile.name;
  const userGender = userProfile.gender;
  const recentEvents = userProfile.user_persona;
  const readerPrompt = $('Conversational tarot').first().json.body.reader_prompt || '';

  // Xây dựng lịch sử hội thoại dạng cặp đôi, ĐÁNH DẤU TURN
  const history = $('Conversational tarot').first().json.body.history || [];
  let historyText = 'Chưa có lịch sử. Đây là tin nhắn đầu tiên.';
  if (history.length > 0) {
    let turnCount = 1;
    let historyLines = [];

    for (let i = 0; i < history.length; i++) {
        const msg = history[i];
        if (msg.role === 'user') {
            historyLines.push(`[Turn ${turnCount}] - Khách hàng: "${msg.content}"`);
        } else {
            historyLines.push(`[Turn ${turnCount}] - Tarot Reader: "${msg.content}"`);
            turnCount++; 
        }
    }
    historyText = historyLines.join('\n');
  }

  // Chèn Chân dung năng lượng
  let personaSection = '';
  if (recentEvents && recentEvents.trim() !== '') {
    personaSection = `\n\n### [CHÂN DUNG NĂNG LƯỢNG KHÁCH HÀNG (Do AI đúc kết từ các phiên trước)]\n${recentEvents}`;
  }

  const defaultSystemPrompt = `## ROLE: Master Tarot Reader thấu cảm và sâu sắc\n## TASK: Khách hàng đang trò chuyện hoặc hỏi thêm. Hãy trả lời sâu sắc, giữ đúng vai Tarot Reader.`;
  const narrativeBase = readerPrompt || defaultSystemPrompt;
  const systemPrompt = narrativeBase + `\n\n## USER INFO: Tên: ${userName}, Giới tính: ${userGender}. Hãy gọi tên và chủ động xưng hô một cách linh hoạt, tự nhiên như một người bạn tâm giao (không bị phụ thuộc máy móc vào giới tính, tùy theo phong cách của bạn).` + personaSection + `\n\n## QUY TẮC:\n1. Lời khuyên cần thực tế, hướng thiện và tích cực.\n2. Nếu có lịch sử, hãy tham chiếu để hiểu bối cảnh, nhưng TẬP TRUNG vào tin nhắn mới nhất.\n3. KHÔNG nhắc đến AI hay thuật toán.`;

  const userPrompt = `### 🗣️ TIN NHẮN MỚI NHẤT CỦA KHÁCH HÀNG:\n"${userMsg}"\n\n---\n\n### 📜 LỊCH SỬ HỘI THOẠI TRƯỚC ĐÓ (Sắp xếp từ cũ đến mới):\n${historyText}\n\n---\n\n-> Dựa vào bối cảnh trên, hãy trả lời tin nhắn mới nhất của khách hàng.`;

  item.json.bodyPayload = {
    model: 'n8n2',
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ],
    temperature: 0.8
  };
}

return $input.all();

